const Q_AGRICULTURE_2024_MODEL_II=[{"id": "objective>Agriculture>2024 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fertility of the soil is an important factor in the selection of site for a fish pond because a fertile soil will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encourage the growth of trees within the pond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulate growth of lower plants which are sources of food to fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">add minerals to the water for the fishes resistance to diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent the pond from drying up</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fertility of the soil is an important factor in the selection of site for a fish pond because a fertile soil will stimulate the growth of lower plants which are sources of food to fish. These lower plants, also known as phytoplankton, form the base of the aquatic food chain and provide food for the fish.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2024 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Air sacs are present in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poultry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cattle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air sacs are present in poultry. Air sacs are part of the respiratory system in birds. They allow for a continuous flow of air through the lungs, which is more efficient than the in-and-out flow of air seen in mammals</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gestation period in days of a sow is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">42</div>", "<div style=\"font-family:Cambria;font-size:17px;\">114</div>", "<div style=\"font-family:Cambria;font-size:17px;\">165</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gestation period of a sow (female pig) is approximately 114 days. This is often remembered as 'three months, three weeks, and three days'.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The castrated male cattle is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bull</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heifer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">castrate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The castrated male cattle is referred to as a steer. Castration is the process of removing the testes of the male cattle, and it is done to control breeding and to reduce aggressive behaviour.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of livestock feed needed to prevent either an increase or a decrease in live weight of an animal is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintenance ration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance ration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weaners ration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production ration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maintenance ration is the amount of feed required to keep an animal in a state where it neither gains nor loses weight. It is the minimum amount of feed required to maintain the animal's body functions.</div>", "topic": "ANIMAL NUTRITION : FEEDS AND FEEDING"}, {"id": "objective>Agriculture>2024 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The water-snail is important in the life-cycle of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">roundworm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tapeworm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver fluke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coccidium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liver fluke is a parasitic worm that requires two hosts to complete its life cycle. The first host is a snail, usually a water snail, where the fluke undergoes several developmental stages. The second host is a mammal, usually a sheep or a cow, where the fluke matures and reproduces</div>", "topic": "CROP PESTS : DISEASE-CAUSING ORGANISMS"}, {"id": "objective>Agriculture>2024 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Biological control of insect pests of crops can best be carried out through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of parasites and predators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil fumigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farm sanitation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biological control of insect pests of crops can best be carried out through the use of parasites and predators. This method involves using natural enemies of the pests to control their population. Crop rotation, soil fumigation, and farm sanitation are other methods of pest control, but they do not involve biological control.</div>", "topic": "CROP PESTS"}, {"id": "objective>Agriculture>2024 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The aims of crop improvement include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing yields</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meeting particular needs of growers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meeting the needs of consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing demand for a particular type of crop</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aims of crop improvement do not include reducing demand for a particular type of crop. Crop improvement is aimed at increasing yields, meeting the particular needs of growers (such as disease resistance or drought tolerance), and meeting the needs of consumers (such as improved taste or nutritional content). Reducing demand for a crop would not be a goal of crop improvement.</div>", "topic": "CROP HUSBANDRY : METHODS OF CROP IMPROVEMENT"}, {"id": "objective>Agriculture>2024 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chromosomes in a cell are located in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">golgi body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromosomes are located in the nucleus of a cell. The nucleus is a membrane-bound organelle that contains the cell's chromosomes. Chromosomes are thread-like structures composed of DNA and proteins. They carry the genes that determine the characteristics of the organism.</div>", "topic": "AGRICULTURAL GENETICS : METHODS OF ANIMAL IMPROVEMENT"}, {"id": "objective>Agriculture>2024 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below represents a chain measurement drawing of a school farmland surveyed by students who encountered an obstruction at point C.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The distance between point A and B will be given by  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AC + CD + EB </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CD + DE + EB </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AC + CE + EB </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AC + CD + DE + EB</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This distance between point A and B is given by <br/>    AC+CD+DE+EB </div>", "topic": "FARM SURVEYING AND FARMSTEAD PLANNING : SURVEYING EQUIPMENT"}, {"id": "objective>Agriculture>2024 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the peculiarities of the intestine tract of a fowl is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cloaca</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oesophageal groove</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large intestine</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the peculiarities of the intestine tract of a fowl is the possession of a cloaca. The cloaca is a common chamber and outlet into which the intestinal, urinary, and genital tracts open. It is used to expel wastes and lay eggs in birds.</div>", "topic": "ANATOMY AND PHYSIOLOGY OF FARM ANIMALS : FUNCTIONS OF TISSUES AND ORGANS OF FARM ANIMALS"}, {"id": "objective>Agriculture>2024 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will not be an effect of excessive amount of water content in feeds?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in nutritive value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of toxic products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging growth of moulds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improving quality of such feeds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excessive amount of water content in feeds does not improve the quality of such feeds. Instead, it can lead to a decrease in nutritive value, formation of toxic products, and growth of moulds.</div>", "topic": "ANIMAL NUTRITION : FEEDS AND FEEDING"}, {"id": "objective>Agriculture>2024 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following group of crops can be attacked by smut diseases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sugarcane, maize and banana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rice, maize and guinea corn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guinea corn, sugarcane and rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize, guinea corn and yam</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Smut diseases are a type of fungal disease that primarily affects grains and grasses, including crops like maize, rice, and guinea corn. Therefore, the correct answer is 'rice, maize and guinea corn'. Sugarcane can also be affected by smut, but banana and rubber are not typically susceptible to this type of disease.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The branch of crop production which is normally concerned with crop improvement is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plant breeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plant science</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horticulture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plant protection</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plant breeding is the branch of crop production that is concerned with crop improvement. It involves the manipulation of plant species in order to create desired genotypes and phenotypes for specific purposes. This manipulation involves either controlled pollination, genetic engineering, or both, followed by artificial selection of progeny.</div>", "topic": "AGRICULTURAL GENETICS : METHODS OF CROP IMPROVEMENT"}, {"id": "objective>Agriculture>2024 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the primary function of the gizzard?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">storage of food before digestion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation of ingested food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grinding of ingested food into smaller particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exposure of food to enzymatic digestion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of the gizzard in birds and some other animals is to grind up food. This is because these animals do not have teeth to chew their food, so the gizzard helps to mechanically break down food into smaller particles that can be easily digested.</div>", "topic": "ANIMAL PHYSIOLOGY"}, {"id": "objective>Agriculture>2024 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The act of mating in cattle is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tupping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lambing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The act of mating in cattle is known as service. This term is used to describe the act of a bull mating with a cow. The other terms like tupping, treading, and lambing are related to other animals or different aspects of animal reproduction.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A non-governmental organization involved in agricultural development in West Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Operation Feed the Nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Basin Development Authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural Development Project</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International Institute of Tropical Agriculture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The International Institute of Tropical Agriculture (IITA) is a nonprofit organisation that works with partners to enhance crop quality and productivity, reduce producer and consumer risks, and generate wealth from agriculture, with the ultimate goals of reducing hunger, malnutrition, and poverty</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hormone generally called pregnancy hormone in farm animals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">testosterone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oestrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">progesterone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">androgen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Progesterone is often referred to as the 'pregnancy hormone' in farm animals. It is produced in the ovaries, the placenta (when a woman gets pregnant) and the adrenal glands. It helps prepare your body for conception and pregnancy and regulates the monthly menstrual cycle. It also plays a role in sexual desire.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">New-born animals should be fed with colostrum because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is easily digested</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains antibodies protecting them against diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provides them permanent immunity gainst diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is the first milk produced before birth</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Colostrum is the first form of milk produced by the mammary glands of mammals (including many humans) immediately following delivery of the newborn. New-born animals should be fed with colostrum because it contains antibodies that protect them against diseases. These antibodies are produced by the mother and passed to the baby, providing the baby with a temporary immunity against diseases.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The farm implement represented by the diagram below is a/an <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arrow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ranging pole</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A ranging pole is a long, slender rod usually made of lightweight material like aluminum or fiberglass. It is marked with alternating bands of contrasting colours to enhance visibility.</div>", "topic": "FARM SURVEYING AND FARMSTEAD PLANNING : SURVEYING EQUIPMENT"}, {"id": "objective>Agriculture>2024 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physiological changes that show up during disease attack on crop plants are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">signs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">symptoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">necrosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deformations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The physiological changes that show up during disease attack on crop plants are referred to as symptoms. Symptoms are the plant's response to the disease and can include a wide range of expressions such as wilting, leaf curling, yellowing, stunting, and many others. Signs, on the other hand, are physical evidence of the pathogen, such as fungal spores, bacterial ooze, etc.</div>", "topic": "ANATOMY AND PHYSIOLOGY OF FARM ANIMALS"}, {"id": "objective>Agriculture>2024 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major symptom of onion/twister is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appearance of dark brown spots on leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motting of leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rottening of roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rottening of buds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major symptom of onion/twister is the appearance of dark brown spots on leaves. Onion/twister is a disease that affects onion plants, causing the leaves to twist and curl.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gummosis is caused by a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nematoda</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gummosis is a disease in plants, particularly fruit trees, where sap oozes from the bark, resulting in the formation of amber-like gum deposits. It is primarily caused by fungal infections, hence the correct answer is 'fungus'.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of the components of a goat's stomach is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rumen-reticulum-abomasum-omasum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reticulum-rumen-omasum-abomasum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rumen-reticulum-omasum-abomasum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reticulum-omasum-abomasum-rumen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of the components of a goat's stomach is rumen-reticulum-omasum-abomasum. The rumen is the first part of the stomach and is where fermentation of food occurs. The reticulum is the second part and works with the rumen to further break down food. The omasum is the third part and absorbs water and nutrients. The abomasum is the fourth and final part and is similar to a human stomach.</div>", "topic": "ANATOMY AND PHYSIOLOGY OF FARM ANIMALS : FUNCTIONS OF TISSUES AND ORGANS OF FARM ANIMALS"}, {"id": "objective>Agriculture>2024 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The foot and mouth disease of cattle is caused by a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nematode</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The foot and mouth disease of cattle is caused by a virus. Foot-and-mouth disease (FMD) is a severe, highly contagious viral disease of cattle and swine. It also affects sheep, goats, deer, and other cloven-hooved ruminants. FMD is not recognised as a zoonotic disease.</div>", "topic": "ANIMAL HEALTH : ANIMAL DISEASES"}, {"id": "objective>Agriculture>2024 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tree species commonly planted for pulpwood is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gmelina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cassia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">albizia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tactona</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gmelina is a tree species commonly planted for pulpwood. Pulpwood is the raw material used in the production of paper, and gmelina is often used because it grows quickly and provides high-quality pulp. The other options, cassia, albizia, and tactona, are not typically used for pulpwood.</div>", "topic": "FOREST MANAGEMENT : IMPORTANCE"}, {"id": "objective>Agriculture>2024 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Root-knot disease in tomatoes is caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nematode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Root-knot disease in tomatoes is caused by nematodes. Nematodes are microscopic worms that live in the soil and can cause damage to plant roots, leading to the formation of 'knots' or galls. This can result in stunted growth and reduced yield. The other options, virus, bacterium, and fungus, are not the cause of root-knot disease in tomatoes.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Callosobruchus maculatus is a common pest of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cowpea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">millet</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Callosobruchus maculatus, also known as the cowpea weevil or bruchid, is a beetle species that is a common pest of cowpea. It is known to cause significant damage to stored cowpea grains.</div>", "topic": "CROP PESTS"}, {"id": "objective>Agriculture>2024 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A combine harvester can be used simultaneously to harvest</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legumes and apply fertilizer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grains and eradicate weeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tubers and distribute fertilizer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cereals and winnow grains</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">combine harvester are used in harvesting and cleaning of cereals such as wheat,barley, maize and rice. <br/> The machine simply combines the three major harvesting operations-reaping, threshing and winnowing into a single process</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below represent the digestive tract of a  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sheep</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fowl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram represent the digestive tract of a fowl</div>", "topic": "ANATOMY AND PHYSIOLOGY OF FARM ANIMALS : FUNCTIONS OF TISSUES AND ORGANS OF FARM ANIMALS"}, {"id": "objective>Agriculture>2024 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Swampy lands are most suitable for growing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tomato</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rice is water loving and does well on soils that hold a lot of water - clay, clay-loamy or loamy. So swampy land which is either clay-loamy or loamy soil depending on the location, and retains a lot of water is suitable for growing rice. <br/> Rice is grown in water primarily to stave off pests, and keep weeds away from the rice fields</div>", "topic": "CROP HUSBANDRY : CROPS"}, {"id": "objective>Agriculture>2024 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pasture crop are best used in preparing hay</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">when they are two weeks old</div>", "<div style=\"font-family:Cambria;font-size:17px;\">just before flowering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">just after seed maturation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">after they have started to dry up</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pasture crops are best used in preparing hay just before flowering. This is because at this stage, the nutritional content of the plant is at its peak. The plant has not yet used its stored nutrients for the process of flowering and seed production. Therefore, the hay made from such plants will be rich in nutrients.</div>", "topic": "PASTURE AND FORAGE CROPS"}, {"id": "objective>Agriculture>2024 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Monocotyledonous crops include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil palm, rice and plantain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cowpea, pepper and tomato</div>", "<div style=\"font-family:Cambria;font-size:17px;\">garden egg, cassava and mango</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber, cashew and orange</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monocot plants have only one cotyledon in their seeds. <br/> Monocots include wheat, maize, bamboo, rice, banana, lilies, orchids, and tulips. <br/> Monocot leaves are small and linear, and they create a sheathing at the base of the stem.</div>", "topic": "PASTURE AND FORAGE CROPS"}, {"id": "objective>Agriculture>2024 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Black pod disease of cocoa is controlled by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fumigation of soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farm sanitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">application of herbicide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">application of fungicide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Black pod disease of cocoa is controlled by the application of fungicide. Black pod is a fungal disease that affects cocoa plants. Fungicides are chemicals that kill or inhibit the growth of fungi. Therefore, applying fungicide to the cocoa plants will help to control the spread of the black pod disease.</div>", "topic": "CROP DISEASES"}, {"id": "objective>Agriculture>2024 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To reduce rural-urban migration, the government should </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establish commodity boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide social infrastructure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establish tractor-hiring units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide extension services to farmers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As a strategy, for reducing Rural - Urban Migrations in Nigeria, Government should provide housing and adequate social amenities for the rural dwellers </div>", "topic": "AGRICULTURAL GENETICS : METHODS OF CROP IMPROVEMENT"}, {"id": "objective>Agriculture>2024 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factor does not affect the distribution of pasture grasses?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pest</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind does not affect the distribution of pasture grasses. The distribution of pasture grasses is primarily determined by factors such as soil type, temperature, and the presence of pests or diseases. While wind can play a role in the dispersal of grass seeds, it does not directly affect the distribution of established grasses.</div>", "topic": "PASTURE AND FORAGE CROPS"}, {"id": "objective>Agriculture>2024 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Weed plants which grow on other plants without deriving nutrients from them are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sedge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epiphytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weed plants which grow on other plants without deriving nutrients from them are called epiphytes. Epiphytes are plants that grow on other plants, but unlike parasites, they do not derive nutrients from their hosts. They only use the host plants for physical support. Sedge is a type of grass-like plant, decomposers are organisms that break down dead or decaying organisms, and saprophytes are organisms that feed on decaying organic matter.</div>", "topic": "WEEDS"}, {"id": "objective>Agriculture>2024 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An accessory sex gland in bull is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prostrate gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pituitary gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thyroid gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreatic gland</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In male mammals, the prostate gland is an accessory sex gland that contributes fluid to the ejaculate. The prostate gland is not unique to bulls but is found in all male mammals.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following feedstuff does not contain phosphorous?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blood meal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fish meal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oyster shell</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oyster shell does not contain phosphorous. Phosphorous is an essential mineral for animals, it is found in many feedstuffs including blood meal, limestone, and fish meal. However, oyster shell is primarily composed of calcium carbonate and does not contain significant amounts of phosphorous.</div>", "topic": "ANIMAL NUTRITION : FEED NUTRIENTS AND FUNCTIONS"}, {"id": "objective>Agriculture>2024 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following livestock endoparasite is a hermaphrodite?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liverfluke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trypanosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tapeworm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">roundworm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworms are hermaphrodites, meaning they have both male and female reproductive organs. This allows them to self-fertilize and produce eggs without needing a mate. Liver flukes, trypanosomes, and roundworms are not hermaphrodites.</div>", "topic": "ANIMAL HEALTH : PARASITES"}];
